# MERGE when always called together with no decision between them
# Bad: two calls for what is always a single user intent
def lookup_product_id(sku: str) -> str: ...
def get_product_details(product_id: str) -> dict: ...

# Good: one call, SKU -> full product
def get_product(sku: str) -> dict:
    """Look up a product by SKU and return full details."""
    product_id = lookup_product_id(sku)   # internal implementation detail
    return get_product_details(product_id)


# SPLIT when there's a meaningful decision between steps
# Bad: one monolithic booking tool
def book_flight(origin, destination, date, seat_class, meal, extras) -> dict: ...

# Good: the model checks availability first, then decides whether to book
def check_availability(origin: str, destination: str, date: str) -> dict:
    """Return available flights for a route and date."""
    return {"flights": [{"id": "AA123", "seats": 12, "price": 350}]}

def confirm_booking(flight_id: str, passenger_name: str, seat_class: str = "economy") -> dict:
    """Book a specific flight. Requires flight_id from check_availability."""
    return {"confirmation": "CONF-789", "flight_id": flight_id}

