import anthropic, json
from dataclasses import dataclass, field

@dataclass
class GranularityDiagnostic:
    tool_call_counts: list[int] = field(default_factory=list)

    def record(self, n: int) -> None:
        self.tool_call_counts.append(n)

    def report(self) -> dict:
        if not self.tool_call_counts:
            return {}
        avg = sum(self.tool_call_counts) / len(self.tool_call_counts)
        return {
            "tasks_tested":    len(self.tool_call_counts),
            "avg_calls/task":  round(avg, 2),
            "max_calls":       max(self.tool_call_counts),
            "min_calls":       min(self.tool_call_counts),
            "verdict": (
                "Possibly too fine — consider merging" if avg > 4
                else "Possibly too coarse — consider splitting" if avg < 1.2 and max(self.tool_call_counts) > 3
                else "Looks healthy"
            )
        }

client = anthropic.Anthropic()
diag = GranularityDiagnostic()

TEST_PROMPTS = [
    "What is Alice's role?",
    "Find all active users in the admin group.",
    "Get the profile for bob@example.com.",
]

MY_TOOLS = [
    {
        "name": "get_user",
        "description": "Get full user profile by email.",
        "input_schema": {
            "type": "object",
            "properties": {"email": {"type": "string"}},
            "required": ["email"]
        }
    }
]

for prompt in TEST_PROMPTS:
    messages = [{"role": "user", "content": prompt}]
    calls = 0
    for _ in range(10):
        resp = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=512,
            tools=MY_TOOLS,
            messages=messages
        )
        messages.append({"role": "assistant", "content": resp.content})
        tool_uses = [b for b in resp.content if b.type == "tool_use"]
        calls += len(tool_uses)
        if resp.stop_reason == "end_turn":
            break
        results = [
            {"type": "tool_result", "tool_use_id": b.id,
             "content": json.dumps({"id": "usr_1", "name": "Alice", "role": "admin", "status": "active"})}
            for b in tool_uses
        ]
        messages.append({"role": "user", "content": results})
    diag.record(calls)

print(json.dumps(diag.report(), indent=2))

# Pattern: read + confirm + write (three tools, three decision points)
SAFE_TOOLS = [
    {
        "name": "get_account_balance",
        "description": "Get the current balance of a bank account.",
        "input_schema": {
            "type": "object",
            "properties": {"account_id": {"type": "string"}},
            "required": ["account_id"]
        }
    },
    {
        "name": "preview_transfer",
        "description": "Preview a transfer — returns fees and final amounts without executing.",
        "input_schema": {
            "type": "object",
            "properties": {
                "from_account": {"type": "string"},
                "to_account":   {"type": "string"},
                "amount":       {"type": "number"}
            },
            "required": ["from_account", "to_account", "amount"]
        }
    },
    {
        "name": "execute_transfer",
        "description": "Execute a previously previewed transfer. Requires preview_id from preview_transfer.",
        "input_schema": {
            "type": "object",
            "properties": {
                "preview_id":   {"type": "string", "description": "ID returned by preview_transfer"},
                "confirmed_by": {"type": "string", "description": "User who confirmed the transfer"}
            },
            "required": ["preview_id", "confirmed_by"]
        }
    }
]
# Splitting into 3 tools means the model MUST go through check -> preview -> execute.
# Each step is logged separately, and you can add human-in-the-loop at execute_transfer.
